+    pub request_timeout_ms: u64,
+    /// Maximum wait for first response byte.
+    pub first_byte_timeout_ms: u64,
+    /// Maximum idle gap between streamed response chunks.
+    pub between_chunks_timeout_ms: u64,
+}
